<template>
<div class="container">
    <el-breadcrumb separator-class="el-icon-arrow-right">
        <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
        <el-breadcrumb-item>活动管理</el-breadcrumb-item>
        <el-breadcrumb-item>活动列表</el-breadcrumb-item>
    </el-breadcrumb>

    <el-card>
        <el-button type="primary">主要按钮</el-button>
        <el-table :data="rulesList" border stripe height="450">
            <el-table-column type="expand" label="open" width="80">
                <template slot-scope="scope">
                    <el-row :class="['bottom',index===0?'top':'','vcenter']" v-for="(item,index) in scope.row.children" :key="item.id">
                        <el-col :span="5">
                            <el-tag closable @close="removeRight(scope.row,item.id)">{{item.authName}}</el-tag>
                            <i class="el-icon-caret-right"></i>
                        </el-col>
                        <el-col :span="19" >
                            <el-row :class="[index===0?'':'top','vcenter']" v-for="(it,index) in item.children" :key="it.id">
                                <el-col :span="6">
                                    <el-tag type="success" closable @close="removeRight(scope.row,it.id)">{{it.authName}}</el-tag>
                                    <i class="el-icon-caret-right"></i>
                                </el-col>
                                <el-col :span="18">
                                        <el-tag v-for="(i,index) in it.children" :key="i.id" type="warning" closable @close="removeRight(scope.row,i.id)">{{i.authName}}</el-tag>
                                </el-col>
                            </el-row>
                        </el-col>
                    </el-row>
                </template>
            </el-table-column>
            <el-table-column type="index" label="rank" width="80">
            </el-table-column>
            <el-table-column prop="roleName" label="角色名称">
            </el-table-column>
            <el-table-column prop="roleDesc" label="技术负责人">
            </el-table-column>
            <el-table-column label="操作" width="300">
                <template slot-scope="scope">
                    <el-button type="primary" icon="el-icon-edit" size="mini">编辑</el-button>
                    <el-button type="warning" icon="el-icon-delete" size="mini">删除</el-button>
                    <el-button type="danger" icon="el-icon-setting" size="mini" @click="showSetRightDialog(scope.row)">分配权限</el-button>
                </template>
            </el-table-column>
        </el-table>
    </el-card>
    <el-dialog title="提示" :visible.sync="dialogVisible" width="30%" :before-close="handleClose">
        <el-tree :data="rightLIst" show-checkbox node-key="id" default-expand-all :default-checked-keys="defaultKeyId" :props="treeProps" ref="treeRef">
        </el-tree>
        <span slot="footer" class="dialog-footer">
            <el-button @click="handleClose">取 消</el-button>
            <el-button type="primary" @click="setRight()">确 定</el-button>
        </span>
    </el-dialog>
</div>
</template>

<script>
export default{
    data(){
        return{
            rulesList:[],
            dialogVisible:false,
            rightLIst:[],
            treeProps:{
                label:'authName',
                children:'children'
            },
            roleID:null,
            defaultKeyId:[]
        }
    },
    created(){
        this.getRulesList()
    },
    methods:{
        async getRulesList(){
            const{data:result}=await this.$http.get('roles')
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            this.rulesList=result.data
        },
        async removeRight(role,roleRightID){
            const confirmResult= await this.$confirm('此操作将永久删除该文件, 是否继续?', '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
            }).catch(err =>{return err})
            // console.log(confirmResult);
            if(confirmResult=='cancel'){return this.$message.info('用户取消')}
            else if(confirmResult=='confirm'){
                const{data:result}=await this.$http.delete(`roles/${role.id}/rights/${roleRightID}`)
                if(result.meta.status!==200){return this.$message.error('取消权限失败');}
                else{
                    // this.getRulesList()
                    role.children=result.data
                    return this.$message.success('取消权限成功')
                }
            }
        },
        async showSetRightDialog(role){
            this.dialogVisible = true
            this.roleID=role.id
            const{data:result}=await this.$http.get('rights/tree')
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            this.rightLIst=result.data
            this.getLeafKey(role,this.defaultKeyId)
        },
        handleClose(){
            // 清空defaultKeyId数组元素
            this.defaultKeyId=[]
            this.dialogVisible = false
        },
        // 递归函数获取树形数组对象所有三级权限的id
        // 这个方法必须先定义才能被后面的函数使用 
        getLeafKey(node,arr){
            // 如果节点下面没有子节点就说明是三级节点
            if(!node.children){
                return arr.push(node.id)
            }
            // 切记没有return就是一个死循环
            node.children.forEach((item)=>{
                this.getLeafKey(item,arr)
            })
        },
        async setRight(){
            // 切记请求体字符串以逗号分隔，请求体后台没有进行数据验证，烦的一比
            const key=[...this.$refs.treeRef.getCheckedKeys(),...this.$refs.treeRef.getHalfCheckedKeys()].join(',')
            // console.log(key);
            const{data:result}=await this.$http.post(`roles/${this.roleID}/rights`,{rids:key})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}

            // this.defaultKeyId=[]
            this.getRulesList()
            this.dialogVisible = false
        }
    }
}
</script>

<style lang="less" scoped>
.container{
    padding: 20px;
    width: 100%;
    background-color: aliceblue;
    box-sizing: border-box;
    .el-breadcrumb{
        font-size: 12px;
    }
    .el-card{
        margin: 20px 0 20px 0;
        padding: 10px;
        .el-table{
            margin-top: 20px;
            .el-tag{
                margin: 10px;
                
            }
        }
    }
}
.vcenter{
    display: flex;
    align-items: center;
}
.top{
                    border-top:1px solid #ddd ;
                }
                .bottom{
                    border-bottom:1px solid #ddd ;
                }
</style>