<template>
    <div class="container">
        <!-- 面包屑导航 -->
        <el-breadcrumb separator-class="el-icon-arrow-right">
            <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item>用户管理</el-breadcrumb-item>
            <el-breadcrumb-item>用户列表</el-breadcrumb-item>
        </el-breadcrumb>
        <el-card>
            <el-row :gutter="20">
                <el-col :span="10">
                    <el-input placeholder="请输入内容" v-model="queryInfo.query" clearable>
                        <el-button slot="append" icon="el-icon-search" @click="getUserList()"></el-button>
                    </el-input>
                </el-col>
                <el-col :span="4">
                    <el-button type="primary" @click="dialogVisible=true">添加用户</el-button>
                </el-col>
            </el-row>
            <el-table :data="userInfo" border stripe height="450">
                <el-table-column prop="username" label="用户名称">
                </el-table-column>
                <el-table-column prop="email" label="邮箱">
                </el-table-column>
                <el-table-column prop="mobile" label="电话">
                </el-table-column>
                <el-table-column prop="role_name" label="权限名称">
                </el-table-column>
                <el-table-column prop="mg_state" label="状态">
                    <template slot-scope="scope">
                        <el-switch v-model="scope.row.mg_state" active-color="#13ce66" inactive-color="#ff4949" @change="userStatusChange(scope.row)">
                        </el-switch>
                    </template>
                </el-table-column>
                <el-table-column label="操作" width="180">
                    <template slot-scope="scope">
                        <el-tooltip class="item" effect="dark" content="修改" placement="top">
                            <el-button type="primary" icon="el-icon-edit" size="mini" @click="showEditDialog(scope.row.id)"></el-button>
                        </el-tooltip>
                        <el-tooltip class="item" effect="dark" content="删除" placement="top">
                            <el-button type="danger" icon="el-icon-delete" size="mini" @click="removeUser(scope.row.id)"></el-button>
                        </el-tooltip>
                        <el-tooltip class="item" effect="dark" content="设置" placement="top">
                            <el-button type="warning" icon="el-icon-setting" size="mini" @click="setRole(scope.row)"></el-button>
                        </el-tooltip>                       
                    </template>
                </el-table-column>
            </el-table>
            <el-pagination @size-change="handleSizeChange" @current-change="handleCurrentChange" :current-page="queryInfo.pagenum" :page-sizes="[1, 2, 5,10]" :page-size="queryInfo.pagesize" layout="total, sizes, prev, pager, next, jumper" :total="total">
            </el-pagination>
        </el-card>


        <el-dialog title="添加用户" :visible.sync="dialogVisible" width="50%" @close="addFormClosed">
            <el-form ref="addFormRef" :model="addForm" :rules="addFormRules" label-width="80px">
                <el-form-item label="用户名" prop="username">
                    <el-input v-model="addForm.username"></el-input>
                </el-form-item>
                <el-form-item label="密码" prop="password">
                    <el-input v-model="addForm.password"></el-input>
                </el-form-item>
                <el-form-item label="邮箱"  prop="email">
                    <el-input v-model="addForm.email"></el-input>
                </el-form-item>
                <el-form-item label="电话" prop="mobile">
                    <el-input v-model="addForm.mobile"></el-input>
                </el-form-item>
            </el-form>
            <span slot="footer" class="dialog-footer">
                <el-button @click="dialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="addUser">确 定</el-button>
            </span>
        </el-dialog>

        <el-dialog title="修改用户" :visible.sync="editDialogVisible" width="50%" @close="editFormClosed">
            <el-form  :model="editForm" :rules="editFormRules" ref="editFormRef" label-width="80px">
                <el-form-item label="用户名">
                    <el-input disabled v-model="editForm.username"></el-input>
                </el-form-item>
                <el-form-item label="邮箱" prop="email" >
                    <el-input v-model="editForm.email" ></el-input>
                </el-form-item>
                <el-form-item label="电话" prop="mobile">
                    <el-input v-model="editForm.mobile"></el-input>
                </el-form-item>
            </el-form>
            <span slot="footer" class="dialog-footer">
                <el-button @click="editDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="editUser">确 定</el-button>
            </span>
        </el-dialog>

        <el-dialog title="提示" :visible.sync="setRoleDialogVisible" width="50%" @close="setRoleDialogClose()">
            <span>
                <p>当前用户名称:    {{userInfoData.username}}</p>
                <p>当前角色名称:    {{userInfoData.role_name}}</p>
                <p>分配新的角色:   
                        <el-select v-model="selectedRoleID" filterable placeholder="请选择" clearable>
                            <el-option
                                v-for="item in rolesList"
                                :key="item.id"
                                :label="item.roleName"
                                :value="item.id">
                            </el-option>
                        </el-select>
                </p>
            </span>
            <span slot="footer" class="dialog-footer">
                <el-button @click="setRoleDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="saveRoleInfo()">确 定</el-button>
            </span>
        </el-dialog>
    </div>
</template>
<script>
    export default{
        data(){
            var checkEmail=(role,value,callback)=>{
                const regEmail=/^[A-Za-z0-9\u4e00-\u9fa5]+@[a-zA-Z0-9_-]+(\.[a-zA-Z0-9_-]+)+$/
                if(regEmail.test(value)){return callback()}
                else{callback(new Error("请输入合法邮箱"))}
            }
            var checkMobile=(role,value,callback)=>{
                const regMobile=/^(?:(?:\+|00)86)?1(?:(?:3[\d])|(?:4[5-79])|(?:5[0-35-9])|(?:6[5-7])|(?:7[0-8])|(?:8[\d])|(?:9[189]))\d{8}$/
                if(regMobile.test(value)){return callback()}
                else{callback(new Error("请输入合法手机号"))}
            }
            return{
                queryInfo:{
                    query:null,
                    pagenum:1,
                    pagesize:2
                },
                userInfo:[],
                total:null,
                dialogVisible:false,
                editDialogVisible:false,
                setRoleDialogVisible:false,
                userInfoData:{},
                selectedRoleID:null,
                rolesList:null,
                addForm:{
                    username:null,
                    password:null,
                    email:null,
                    mobile:null
                },
                editForm:{},
                addFormRules:{
                    username:[
                        { required: true, message: '用户名为必填项', trigger: 'blur' },
                        { min: 3, max: 8, message: '长度在 3 到 5 个字符', trigger: 'blur' }
                    ],
                    password:[
                        { required: true, message: '密码为必填项', trigger: 'blur' },
                        { min: 6, max: 12, message: '长度在 6 到 12 个字符', trigger: 'blur' }
                    ],
                    email:[
                        { required: true, message: '密码为必填项', trigger: 'blur' },
                        { validator:checkEmail,trigger:'blur'}
                    ],
                    mobile:[
                        { required: true, message: '密码为必填项', trigger: 'blur' },
                        { validator:checkMobile,trigger:'blur'}
                    ]
                },
                editFormRules:{
                    email:[
                        { required: true, message: '密码为必填项', trigger: 'blur' },
                        { validator:checkEmail,trigger:'blur'}
                    ],
                    mobile:[
                        { required: true, message: '密码为必填项', trigger: 'blur' },
                        { validator:checkMobile,trigger:'blur'}
                    ]
                }
            }
        },
        created(){
            this.getUserList()
        },
        methods:{
            async getUserList(){
               const {data:result} = await this.$http.get('users',{params:this.queryInfo})
               if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
               else{this.$message.success(result.meta.msg);}
               this.userInfo=result.data.users
               this.total=result.data.total
            },
            handleSizeChange(val) {
                this.queryInfo.pagesize=val
                this.getUserList()
            },
            handleCurrentChange(val) {
                this.queryInfo.pagenum=val
                this.getUserList()
            },
            async userStatusChange(val){
                const {data:result}=await this.$http.put(`users/${val.id}/state/${val.mg_state}`)
                if(result.meta.status!==200){
                    val.mg_state=!val.mg_state
                    return this.$message.error(result.meta.msg);
                }
                else{this.$message.success(result.meta.msg);}
            },
            addFormClosed(){
                this.$refs.addFormRef.resetFields()
            },
            editFormClosed(){
                this.$refs.editFormRef.resetFields()
            },
            addUser(){
                this.$refs.addFormRef.validate(async (valid)=>{
                        if(valid){
                            // 发请求
                            const {data:result}=await this.$http.post('users',this.addForm)
                            if(result.meta.status!==201){return this.$message.error("添加用户失败")}
                            else{
                                this.$message.success("添加用户成功")
                            }
                        }else{
                            this.$message.error('请确保表单每项输入正确')
                        }
                        this.dialogVisible = false
                        this.getUserList()
                    })
            },
            async showEditDialog(id){
                this.editDialogVisible=true
                const{data:result}=await this.$http.get('users/'+id)
                if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                else{
                    this.editForm=result.data
                    this.$message.success(result.meta.msg)
                }
            },
            editUser(id){
                this.$refs.editFormRef.validate(async (valid)=>{
                        if(valid){
                            // 发请求
                            const {data:result}=await this.$http.put('users/'+this.editForm.id,{email:this.editForm.email,mobile:this.editForm.mobile})
                            if(result.meta.status!==200){return this.$message.error(result.meta.msg)}
                            else{
                                this.$message.success(result.meta.msg)
                            }
                        }else{
                            this.$message.error('请确保表单每项输入正确')
                        }
                        this.editDialogVisible = false
                        this.getUserList()
                    })
            },
            removeUser(id){
                this.$confirm('此操作将永久删除该文件, 是否继续?', '提示', {
                    confirmButtonText: '确定',
                    cancelButtonText: '取消',
                    type: 'warning'
                }).then(async () => {
                    const{data:result}=await this.$http.delete('users/'+id)
                    if(result.meta.status!==200){return this.$message.error(result.meta.msg)}
                    else{
                        this.$message.success(result.meta.msg)
                    }
                    this.getUserList()
                }).catch((error) => {
                    return error        
                });
                
            },
            async setRole(userInfo){
                this.setRoleDialogVisible=true
                this.userInfoData=userInfo
                const {data:result}=await this.$http.get('roles')
                if(result.meta.status!==200){return this.$message.error(result.meta.msg)}
                else{
                    this.$message.success(result.meta.msg)
                }
                this.rolesList=result.data
                // console.log(this.rolesList);
            },
            async saveRoleInfo(){
                if(!this.selectedRoleID){
                    return this.$message.warning('请选择权限')
                }
                const {data:result}=await this.$http.put(`users/${this.userInfoData.id}/role`,{rid:this.selectedRoleID})
                if(result.meta.status!==200){return this.$message.error(result.meta.msg)}
                else{
                    this.$message.success(result.meta.msg)
                }
                this.getUserList()
                this.setRoleDialogVisible = false
            },
            setRoleDialogClose(){
                this.selectedRoleID=null
                this.userInfoData={}
                this.setRoleDialogVisible = false
            }
        }
    }
</script>
<style lang="less" scoped>
.container{
    background-color: aliceblue;
    width: 100%;
    padding: 20px;
    box-sizing: border-box;
}
.el-breadcrumb{
    font-size: 12px;
}
.el-card{
    margin: 20px 0 20px 0;
}
.el-table{
    margin-top: 20px;
}
.el-pagination{
    margin-left: 50%;
    transform: translate(-50%,10px);
}
</style>